import{_ as h,g as t,f as i,z as c}from"./chunks/framework.5qxeQQbV.js";const l=JSON.parse('{"title":"Kinh Chuyển Pháp Luân","description":"Bài pháp đầu tiên của Đức Phật tại vườn Lộc Uyển, trình bày Tứ Diệu Đế.","frontmatter":{"code":"SN 56.11","title":"Kinh Chuyển Pháp Luân","pali":"Dhammacakkappavattana Sutta","group":"Đạo tương ưng","translation":"thich-minh-chau","book":"tuong-ung-bo","description":"Bài pháp đầu tiên của Đức Phật tại vườn Lộc Uyển, trình bày Tứ Diệu Đế."},"headers":[],"relativePath":"kinh/tuong-ung-bo/thich-minh-chau/sn-56-11-kinh-chuyen-phap-luan.md","filePath":"kinh/tuong-ung-bo/thich-minh-chau/sn-56-11-kinh-chuyen-phap-luan.md","lastUpdated":1782983601000}'),o={name:"kinh/tuong-ung-bo/thich-minh-chau/sn-56-11-kinh-chuyen-phap-luan.md"};function a(p,n,g,u,e,r){return t(),i("div",null,[...n[0]||(n[0]=[c("<p><em>Như vầy tôi nghe.</em></p><p>Một thời Thế Tôn trú tại Benares, tại vườn Lộc Uyển, chỗ các con nai. Tại đó, Thế Tôn thuyết pháp cho năm vị Tỳ-kheo:</p><p>&quot;Này các Tỷ-kheo, hai cực đoan này không nên theo đuổi bởi những ai xuất gia:</p><p><strong>Thứ nhất</strong>, theo đuổi sự hưởng thụ trong các dục lạc thế tục — thấp hèn, phàm tục, thuộc phàm phu, không xứng bậc Thánh.</p><p><strong>Thứ hai</strong>, tự hành hạ thân thể — đau khổ, không xứng bậc Thánh.</p><p>Này các Tỷ-kheo, Như Lai đã từ bỏ hai cực đoan này, thấy được con đường giữa — Tám Thánh Đạo, dẫn đến an lạc, trí tuệ, giác ngộ, Niết-bàn.</p><p>Đó là: <strong>Chánh kiến, Chánh tư duy, Chánh ngữ, Chánh nghiệp, Chánh mạng, Chánh tinh tấn, Chánh niệm, Chánh định.</strong></p><p>Này các Tỷ-kheo, đây là Tứ Diệu Đế đã được Như Lai giác ngộ, cần được hiểu rõ, cần được thành tựu:</p><ol><li><strong>Khổ đế</strong> — sinh là khổ, già là khổ, bệnh là khổ, chết là khổ…</li><li><strong>Tập đế</strong> — tham ái là nguyên nhân của khổ</li><li><strong>Diệt đế</strong> — sự đoạn tận tham ái</li><li><strong>Đạo đế</strong> — con đường dẫn đến đoạn tận khổ — chính là Tám Thánh Đạo</li></ol><p>Khi pháp này được thuyết giảng, Tỳ-kheo Kondañña đã giác ngộ: <em>&quot;Những gì có tánh sinh, đều có tánh diệt.&quot;</em></p><hr>",11)])])}const m=h(o,[["render",a]]);export{l as __pageData,m as default};
